import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Word, ScoreData } from '../types';
import { playAmericanPronunciation } from '../services/geminiService';

interface SpellingGameProps {
  words: Word[];
  onFinish: (scoreData: ScoreData) => void;
}

const SpellingGame: React.FC<SpellingGameProps> = ({ words, onFinish }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedLetters, setSelectedLetters] = useState<string[]>([]);
  const [scrambledLetters, setScrambledLetters] = useState<string[]>([]);
  const [hasFailedThisWord, setHasFailedThisWord] = useState(false);
  const [correctFirstTryCount, setCorrectFirstTryCount] = useState(0);
  const [isWrong, setIsWrong] = useState(false);

  const currentWord = words[currentIndex].word;

  const shuffleLetters = useCallback((word: string) => {
    return word.split('').sort(() => Math.random() - 0.5);
  }, []);

  const initWord = useCallback(() => {
    setScrambledLetters(shuffleLetters(currentWord));
    setSelectedLetters([]);
    setHasFailedThisWord(false);
    setIsWrong(false);
    playAmericanPronunciation(currentWord);
  }, [currentWord, shuffleLetters]);

  useEffect(() => {
    initWord();
  }, [currentIndex, initWord]);

  const handleLetterClick = (letter: string, index: number) => {
    if (isWrong) return;

    const newScrambled = [...scrambledLetters];
    newScrambled.splice(index, 1);
    setScrambledLetters(newScrambled);

    const newSelected = [...selectedLetters, letter];
    setSelectedLetters(newSelected);

    // Check if finished
    if (newSelected.length === currentWord.length) {
      if (newSelected.join('') === currentWord) {
        // Success
        if (!hasFailedThisWord) {
          setCorrectFirstTryCount(prev => prev + 1);
        }

        setTimeout(() => {
          if (currentIndex < words.length - 1) {
            setCurrentIndex(prev => prev + 1);
          } else {
            // Final finish
            const finalScore = (!hasFailedThisWord ? correctFirstTryCount + 1 : correctFirstTryCount) * 2;
            onFinish({
              totalScore: finalScore,
              correctFirstTry: !hasFailedThisWord ? correctFirstTryCount + 1 : correctFirstTryCount,
              totalWords: words.length
            });
          }
        }, 600);
      } else {
        // Wrong
        setIsWrong(true);
        setHasFailedThisWord(true);
        setTimeout(() => {
          // Reset current word attempt
          setSelectedLetters([]);
          setScrambledLetters(shuffleLetters(currentWord));
          setIsWrong(false);
        }, 800);
      }
    }
  };

  const undoLetter = (index: number) => {
    if (isWrong) return;
    const letter = selectedLetters[index];
    const newSelected = [...selectedLetters];
    newSelected.splice(index, 1);
    setSelectedLetters(newSelected);
    setScrambledLetters(prev => [...prev, letter]);
  };

  const progress = ((currentIndex) / words.length) * 100;

  return (
    <div className="max-w-4xl mx-auto px-4 py-8 flex flex-col items-center space-y-12">
      {/* Progress Bar */}
      <div className="w-full bg-slate-200 rounded-full h-4 relative overflow-hidden shadow-inner">
        <div 
          className="h-full bg-indigo-500 transition-all duration-500 ease-out"
          style={{ width: `${progress}%` }}
        />
        <div className="absolute top-0 right-4 h-full flex items-center">
          <span className="text-[10px] font-bold text-slate-600 uppercase">
            Word {currentIndex + 1} / {words.length}
          </span>
        </div>
      </div>

      {/* Audio Button */}
      <button 
        onClick={() => playAmericanPronunciation(currentWord)}
        className="w-24 h-24 bg-white rounded-full shadow-lg border-4 border-indigo-100 flex items-center justify-center hover:scale-110 hover:shadow-indigo-200 transition-all active:scale-95 group"
      >
        <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 text-indigo-500 group-hover:text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
        </svg>
      </button>

      {/* Slots (Underlines) */}
      <div className="flex flex-wrap justify-center gap-3 min-h-[80px]">
        {currentWord.split('').map((_, i) => (
          <div 
            key={`slot-${i}`}
            onClick={() => i < selectedLetters.length && undoLetter(i)}
            className={`w-14 h-16 border-b-4 flex items-center justify-center text-3xl font-bold cursor-pointer transition-all
              ${isWrong ? 'border-red-400 text-red-500 animate-shake' : 'border-indigo-200 text-indigo-900 hover:border-indigo-400'}
              ${selectedLetters[i] ? 'bg-white rounded-t-xl shadow-sm' : 'bg-transparent'}
            `}
          >
            {selectedLetters[i] || ''}
          </div>
        ))}
      </div>

      {/* Letter Pool */}
      <div className="flex flex-wrap justify-center gap-4 p-8 bg-indigo-50/50 rounded-3xl border-2 border-dashed border-indigo-200 w-full">
        {scrambledLetters.map((letter, i) => (
          <button
            key={`pool-${letter}-${i}`}
            onClick={() => handleLetterClick(letter, i)}
            className="w-14 h-14 bg-white rounded-xl shadow-md border-2 border-indigo-100 text-2xl font-bold text-indigo-700 
                       hover:translate-y-[-4px] hover:shadow-lg hover:border-indigo-300 transition-all active:scale-90"
          >
            {letter}
          </button>
        ))}
        {scrambledLetters.length === 0 && (
            <div className="text-slate-400 font-medium italic">All letters used!</div>
        )}
      </div>

      {/* Hint */}
      <p className="text-slate-400 text-sm font-medium">
        Click a selected letter to return it to the pool.
      </p>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .animate-shake {
          animation: shake 0.2s ease-in-out 4;
        }
      `}</style>
    </div>
  );
};

export default SpellingGame;

import React, { useEffect, useState } from 'react';
import { ScoreData } from '../types';
import { getAIFeedback } from '../services/geminiService';

interface ResultsProps {
  scoreData: ScoreData;
  onRestart: () => void;
}

const Results: React.FC<ResultsProps> = ({ scoreData, onRestart }) => {
  const [aiFeedback, setAiFeedback] = useState("正在生成评价...");
  const { totalScore, correctFirstTry, totalWords } = scoreData;

  useEffect(() => {
    const fetchFeedback = async () => {
      const fb = await getAIFeedback(totalScore);
      setAiFeedback(fb);
    };
    fetchFeedback();
  }, [totalScore]);

  const getRank = () => {
    if (totalScore >= 90) return { title: '拼写宗师 (Master)', color: 'text-red-500', bg: 'bg-red-50' };
    if (totalScore >= 80) return { title: '卓越之星 (Excellent)', color: 'text-orange-500', bg: 'bg-orange-50' };
    if (totalScore >= 60) return { title: '进取少年 (Good Job)', color: 'text-blue-500', bg: 'bg-blue-50' };
    if (totalScore >= 40) return { title: '词汇学徒 (On Track)', color: 'text-green-500', bg: 'bg-green-50' };
    return { title: '继续加油 (Keep Going)', color: 'text-slate-500', bg: 'bg-slate-50' };
  };

  const rank = getRank();

  return (
    <div className="max-w-2xl mx-auto p-10 flex flex-col items-center animate-in zoom-in duration-500">
      <div className={`w-48 h-48 rounded-full flex flex-col items-center justify-center shadow-2xl border-8 border-white ${rank.bg} mb-8 transform hover:rotate-6 transition-transform`}>
        <span className={`text-6xl font-kids ${rank.color}`}>{totalScore}</span>
        <span className="text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Points</span>
      </div>

      <h2 className={`text-3xl font-kids mb-2 ${rank.color}`}>{rank.title}</h2>

      <div className="bg-white rounded-3xl p-8 shadow-sm border border-slate-100 w-full mb-8 text-center space-y-4">
        <div className="grid grid-cols-2 gap-4">
          <div className="p-4 bg-slate-50 rounded-2xl">
            <p className="text-xs text-slate-400 uppercase font-bold mb-1">Total Words</p>
            <p className="text-2xl font-kids text-slate-700">{totalWords}</p>
          </div>
          <div className="p-4 bg-slate-50 rounded-2xl">
            <p className="text-xs text-slate-400 uppercase font-bold mb-1">Perfect First Try</p>
            <p className="text-2xl font-kids text-indigo-500">{correctFirstTry}</p>
          </div>
        </div>

        <div className="pt-4 border-t border-slate-100">
          <p className="text-sm text-slate-500 italic">" {aiFeedback} "</p>
        </div>
      </div>

      <button
        onClick={onRestart}
        className="px-10 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-200 hover:bg-indigo-700 hover:-translate-y-1 active:translate-y-0 transition-all"
      >
        再测一次 (Test Again)
      </button>
    </div>
  );
};

export default Results;

import React, { useState } from 'react';
import { GameState, LexileRange, Word, ScoreData } from './types';
import { LEXILE_WORDS } from './constants';
import LexileSelector from './components/LexileSelector';
import SpellingGame from './components/SpellingGame';
import Results from './components/Results';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [currentWords, setCurrentWords] = useState<Word[]>([]);
  const [scoreData, setScoreData] = useState<ScoreData | null>(null);

  const startTest = (range: LexileRange) => {
    // Randomly pick 50 words from the selected range
    const pool = LEXILE_WORDS[range];
    const shuffled = [...pool].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, 50);

    setCurrentWords(selected);
    setGameState(GameState.PLAYING);
  };

  const handleFinish = (data: ScoreData) => {
    setScoreData(data);
    setGameState(GameState.FINISHED);
  };

  const resetGame = () => {
    setGameState(GameState.START);
    setScoreData(null);
    setCurrentWords([]);
  };

  return (
    <div className="min-h-screen py-12 px-4 selection:bg-indigo-100">
      <header className="max-w-6xl mx-auto mb-12 flex justify-between items-center">
        <div className="flex items-center space-x-3 cursor-pointer" onClick={resetGame}>
          <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center shadow-lg shadow-indigo-100">
            <span className="text-white font-kids text-xl">L</span>
          </div>
          <span className="text-2xl font-kids text-indigo-900">Lexile Spelling</span>
        </div>

        {gameState === GameState.PLAYING && (
           <div className="hidden md:block">
             <button 
                onClick={() => { if(confirm('Exit current test?')) resetGame(); }}
                className="text-slate-400 hover:text-red-500 text-sm font-semibold transition-colors"
             >
                Exit Test
             </button>
           </div>
        )}
      </header>

      <main className="max-w-6xl mx-auto">
        {gameState === GameState.START && (
          <LexileSelector onSelect={startTest} />
        )}

        {gameState === GameState.PLAYING && currentWords.length > 0 && (
          <SpellingGame 
            words={currentWords} 
            onFinish={handleFinish} 
          />
        )}

        {gameState === GameState.FINISHED && scoreData && (
          <Results 
            scoreData={scoreData} 
            onRestart={resetGame} 
          />
        )}
      </main>

      {/* Background decoration */}
      <div className="fixed -bottom-24 -left-24 w-96 h-96 bg-indigo-100/30 rounded-full blur-3xl -z-10 animate-pulse"></div>
      <div className="fixed -top-24 -right-24 w-96 h-96 bg-blue-100/30 rounded-full blur-3xl -z-10 animate-pulse delay-700"></div>
    </div>
  );
};

export default App;

