import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { Word, ScoreData } from '../types';
import { playAmericanPronunciation } from '../services/geminiService';

interface SpellingGameProps {
  words: Word[];
  onFinish: (scoreData: ScoreData) => void;
  onBack: () => void;
}

const SpellingGame: React.FC<SpellingGameProps> = ({ words, onFinish, onBack }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  // Using fixed slots: an array of characters or null
  const [selectedLetters, setSelectedLetters] = useState<(string | null)[]>([]);
  const [scrambledLetters, setScrambledLetters] = useState<string[]>([]);
  const [hasFailedThisWord, setHasFailedThisWord] = useState(false);
  const [correctFirstTryCount, setCorrectFirstTryCount] = useState(0);
  const [isWrong, setIsWrong] = useState(false);

  const currentWord = words[currentIndex].word;

  const shuffleLetters = useCallback((word: string) => {
    return word.split('').sort(() => Math.random() - 0.5);
  }, []);

  const initWord = useCallback(() => {
    setScrambledLetters(shuffleLetters(currentWord));
    setSelectedLetters(new Array(currentWord.length).fill(null));
    setHasFailedThisWord(false);
    setIsWrong(false);
    playAmericanPronunciation(currentWord);
  }, [currentWord, shuffleLetters]);

  useEffect(() => {
    initWord();
  }, [currentIndex, initWord]);

  const handleLetterClick = (letter: string, indexInPool: number) => {
    if (isWrong) return;

    // Find first empty slot
    const firstEmptyIndex = selectedLetters.indexOf(null);
    if (firstEmptyIndex === -1) return;

    // Update pool
    const newScrambled = [...scrambledLetters];
    newScrambled.splice(indexInPool, 1);
    setScrambledLetters(newScrambled);

    // Update slots
    const newSelected = [...selectedLetters];
    newSelected[firstEmptyIndex] = letter;
    setSelectedLetters(newSelected);

    // Check if word is fully filled
    if (newSelected.filter(l => l !== null).length === currentWord.length) {
      const spelledWord = newSelected.join('');
      if (spelledWord === currentWord) {
        if (!hasFailedThisWord) {
          setCorrectFirstTryCount(prev => prev + 1);
        }

        setTimeout(() => {
          if (currentIndex < words.length - 1) {
            setCurrentIndex(prev => prev + 1);
          } else {
            const finalCorrect = !hasFailedThisWord ? correctFirstTryCount + 1 : correctFirstTryCount;
            onFinish({
              totalScore: finalCorrect * 20, // Adjusted scoring for 5 words: 5 * 20 = 100
              correctFirstTry: finalCorrect,
              totalWords: words.length
            });
          }
        }, 600);
      } else {
        setIsWrong(true);
        setHasFailedThisWord(true);
        setTimeout(() => {
          // Failure resets the word but keeps history that this word failed first try
          setSelectedLetters(new Array(currentWord.length).fill(null));
          setScrambledLetters(shuffleLetters(currentWord));
          setIsWrong(false);
        }, 800);
      }
    }
  };

  const undoLetter = (indexInSlot: number) => {
    if (isWrong || selectedLetters[indexInSlot] === null) return;

    const letter = selectedLetters[indexInSlot];
    const newSelected = [...selectedLetters];
    newSelected[indexInSlot] = null; // Only clear this specific slot
    setSelectedLetters(newSelected);

    // Put letter back into pool
    setScrambledLetters(prev => [...prev, letter!]);
  };

  const progress = ((currentIndex) / words.length) * 100;

  // Responsive sizes based on word length
  const slotSizeClass = currentWord.length > 8 ? 'w-10 h-12 text-xl' : 'w-12 h-14 md:w-16 md:h-20 text-2xl md:text-3xl';
  const poolSizeClass = currentWord.length > 8 ? 'w-12 h-12 text-xl' : 'w-14 h-14 md:w-16 md:h-16 text-2xl';

  return (
    <div className="max-w-4xl mx-auto px-2 py-4 flex flex-col items-center space-y-6 md:space-y-8 animate-in slide-in-from-bottom-4 duration-500">
      {/* Navigation Header */}
      <div className="w-full flex justify-between items-center mb-2 px-2">
        <button 
          onClick={onBack}
          className="flex items-center space-x-1 text-indigo-600 hover:text-indigo-800 font-bold transition-colors group"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 transform group-hover:-translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
          </svg>
          <span className="text-sm">Back</span>
        </button>
        <span className="text-[10px] md:text-xs font-bold text-slate-400 uppercase tracking-widest">
          Vocabulary Training
        </span>
      </div>

      {/* Progress Bar Container */}
      <div className="w-full px-2">
        <div className="w-full bg-white rounded-full h-2 md:h-3 relative overflow-hidden shadow-sm border border-slate-100">
          <div 
            className="h-full bg-indigo-500 transition-all duration-500 ease-out"
            style={{ width: `${progress}%` }}
          />
        </div>
        <div className="w-full flex justify-between mt-2 text-[9px] md:text-[10px] font-bold text-slate-400 uppercase tracking-tighter">
          <span>Overall Progress</span>
          <span>Word {currentIndex + 1} of {words.length}</span>
        </div>
      </div>

      {/* Audio Section */}
      <div className="flex flex-col items-center space-y-3 pt-2">
        <button 
          onClick={() => playAmericanPronunciation(currentWord)}
          className="w-20 h-20 md:w-28 md:h-28 bg-white rounded-full shadow-lg border-4 border-indigo-50 flex items-center justify-center hover:scale-105 hover:shadow-indigo-100 transition-all active:scale-95 group"
          aria-label="Play pronunciation"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-10 w-10 md:h-12 md:w-12 text-indigo-500 group-hover:text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
          </svg>
        </button>
        <p className="text-indigo-400 text-[10px] font-bold tracking-[0.2em] uppercase">Listen carefully</p>
      </div>

      {/* Spelling Area (Slots) */}
      <div className="flex flex-wrap justify-center gap-2 md:gap-4 min-h-[80px] md:min-h-[100px] w-full pt-4">
        {selectedLetters.map((letter, i) => (
          <div 
            key={`slot-${i}`}
            onClick={() => undoLetter(i)}
            className={`${slotSizeClass} border-b-2 md:border-b-4 flex items-center justify-center font-bold cursor-pointer transition-all
              ${isWrong ? 'border-red-400 text-red-500 animate-shake' : 'border-indigo-100 text-indigo-900 hover:border-indigo-300'}
              ${letter ? 'bg-white rounded-t-xl shadow-md border-indigo-200' : 'bg-indigo-50/20'}
            `}
          >
            {letter || ''}
          </div>
        ))}
      </div>

      {/* Letter Pool - Optimized for responsiveness */}
      <div className="flex flex-wrap justify-center gap-2 md:gap-4 p-4 w-full pt-8">
        {scrambledLetters.map((letter, i) => (
          <button
            key={`pool-${letter}-${i}`}
            onClick={() => handleLetterClick(letter, i)}
            className={`${poolSizeClass} bg-white rounded-xl md:rounded-2xl shadow-sm md:shadow-md border border-slate-100 text-indigo-700 
                       font-bold hover:translate-y-[-4px] hover:shadow-lg hover:border-indigo-200 transition-all active:scale-90`}
          >
            {letter}
          </button>
        ))}
      </div>

      {/* Footer Instructions - Responsive font size */}
      <div className="pt-6 text-center px-4">
        <p className="text-slate-400 text-xs md:text-sm font-medium leading-relaxed">
          Tap letters to spell the word. <br/>
          Tapping a placed letter will return only that letter to the pool.
        </p>
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-6px); }
          75% { transform: translateX(6px); }
        }
        .animate-shake {
          animation: shake 0.2s ease-in-out 3;
        }
      `}</style>
    </div>
  );
};

export default SpellingGame;

import React, { useState } from 'react';
import { GameState, LexileRange, Word, ScoreData } from './types';
import { LEXILE_WORDS } from './constants';
import LexileSelector from './components/LexileSelector';
import SpellingGame from './components/SpellingGame';
import Results from './components/Results';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [currentWords, setCurrentWords] = useState<Word[]>([]);
  const [scoreData, setScoreData] = useState<ScoreData | null>(null);

  const startTest = (range: LexileRange) => {
    const pool = LEXILE_WORDS[range];
    const shuffled = [...pool].sort(() => 0.5 - Math.random());
    // Reduced to 5 words for testing as requested
    const selected = shuffled.slice(0, 5);

    setCurrentWords(selected);
    setGameState(GameState.PLAYING);
  };

  const handleFinish = (data: ScoreData) => {
    setScoreData(data);
    setGameState(GameState.FINISHED);
  };

  const resetGame = () => {
    setGameState(GameState.START);
    setScoreData(null);
    setCurrentWords([]);
  };

  return (
    <div className="h-screen flex flex-col px-4 py-4 md:py-6 selection:bg-indigo-100 transition-colors overflow-hidden relative">
      {/* Header - Fixed Height */}
      <header className="flex-none max-w-6xl w-full mx-auto mb-4 md:mb-6 flex justify-between items-center z-20">
        <div className="flex items-center space-x-2 md:space-x-3 cursor-pointer group" onClick={resetGame}>
          <div className="w-10 h-10 md:w-12 md:h-12 bg-indigo-600 rounded-xl md:rounded-2xl flex items-center justify-center shadow-xl shadow-indigo-100 group-hover:rotate-12 transition-transform">
            <span className="text-white font-kids text-xl md:text-2xl">L</span>
          </div>
          <div>
            <h1 className="text-xl md:text-2xl font-kids text-indigo-900 leading-none">Lexile Master</h1>
            <p className="text-[8px] md:text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">Spelling Challenge</p>
          </div>
        </div>
      </header>

      {/* Main Content - Scrollable only if needed */}
      <main className="flex-1 max-w-6xl w-full mx-auto relative z-10 overflow-y-auto no-scrollbar">
        {gameState === GameState.START && (
          <LexileSelector onSelect={startTest} />
        )}

        {gameState === GameState.PLAYING && currentWords.length > 0 && (
          <SpellingGame 
            words={currentWords} 
            onFinish={handleFinish} 
            onBack={resetGame}
          />
        )}

        {gameState === GameState.FINISHED && scoreData && (
          <Results 
            scoreData={scoreData} 
            onRestart={resetGame} 
          />
        )}
      </main>

      {/* Footer - Fixed at bottom */}
      <footer className="flex-none pt-4 text-center z-20">
        <p className="text-[10px] md:text-xs text-slate-400 font-medium">
          &copy; 2025 Lexile Assessment System v1.0
        </p>
      </footer>

      {/* Decorative background elements */}
      <div className="fixed -bottom-32 -left-32 w-[300px] md:w-[500px] h-[300px] md:h-[500px] bg-indigo-100/40 rounded-full blur-[80px] md:blur-[120px] -z-0 animate-pulse pointer-events-none"></div>
      <div className="fixed -top-32 -right-32 w-[300px] md:w-[500px] h-[300px] md:h-[500px] bg-blue-100/40 rounded-full blur-[80px] md:blur-[120px] -z-0 animate-pulse delay-1000 pointer-events-none"></div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
      `}</style>
    </div>
  );
};

export default App;

