import React, { useState, useEffect, useCallback } from 'react';
import { Word, ScoreData } from '../types';
import { playAmericanPronunciation } from '../services/geminiService';

interface SpellingGameProps {
  words: Word[];
  onFinish: (scoreData: ScoreData) => void;
  onBack: () => void;
}

const SpellingGame: React.FC<SpellingGameProps> = ({ words, onFinish, onBack }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedLetters, setSelectedLetters] = useState<(string | null)[]>([]);
  const [scrambledLetters, setScrambledLetters] = useState<string[]>([]);
  const [hasFailedThisWord, setHasFailedThisWord] = useState(false);
  const [correctFirstTryCount, setCorrectFirstTryCount] = useState(0);
  const [isWrong, setIsWrong] = useState(false);

  const currentWord = words[currentIndex].word;

  const shuffleLetters = useCallback((word: string) => {
    return word.split('').sort(() => Math.random() - 0.5);
  }, []);

  const initWord = useCallback(() => {
    setScrambledLetters(shuffleLetters(currentWord));
    setSelectedLetters(new Array(currentWord.length).fill(null));
    setHasFailedThisWord(false);
    setIsWrong(false);
    playAmericanPronunciation(currentWord);
  }, [currentWord, shuffleLetters]);

  useEffect(() => {
    initWord();
  }, [currentIndex, initWord]);

  const handleLetterClick = (letter: string, indexInPool: number) => {
    if (isWrong) return;

    const firstEmptyIndex = selectedLetters.indexOf(null);
    if (firstEmptyIndex === -1) return;

    const newScrambled = [...scrambledLetters];
    newScrambled.splice(indexInPool, 1);
    setScrambledLetters(newScrambled);

    const newSelected = [...selectedLetters];
    newSelected[firstEmptyIndex] = letter;
    setSelectedLetters(newSelected);

    if (newSelected.filter(l => l !== null).length === currentWord.length) {
      const spelledWord = newSelected.join('');
      if (spelledWord === currentWord) {
        if (!hasFailedThisWord) {
          setCorrectFirstTryCount(prev => prev + 1);
        }

        setTimeout(() => {
          if (currentIndex < words.length - 1) {
            setCurrentIndex(prev => prev + 1);
          } else {
            const finalCorrect = !hasFailedThisWord ? correctFirstTryCount + 1 : correctFirstTryCount;
            onFinish({
              totalScore: finalCorrect * 20, 
              correctFirstTry: finalCorrect,
              totalWords: words.length
            });
          }
        }, 600);
      } else {
        setIsWrong(true);
        setHasFailedThisWord(true);
        setTimeout(() => {
          setSelectedLetters(new Array(currentWord.length).fill(null));
          setScrambledLetters(shuffleLetters(currentWord));
          setIsWrong(false);
        }, 800);
      }
    }
  };

  const undoLetter = (indexInSlot: number) => {
    if (isWrong || selectedLetters[indexInSlot] === null) return;

    const letter = selectedLetters[indexInSlot];
    const newSelected = [...selectedLetters];
    newSelected[indexInSlot] = null; 
    setSelectedLetters(newSelected);

    setScrambledLetters(prev => [...prev, letter!]);
  };

  const progress = ((currentIndex) / words.length) * 100;

  // Optimized responsive sizes
  const isLongWord = currentWord.length > 8;
  const slotSizeClass = isLongWord 
    ? 'w-8 h-10 md:w-10 md:h-12 text-lg md:text-xl' 
    : 'w-10 h-12 md:w-16 md:h-20 text-xl md:text-3xl';
  const poolSizeClass = isLongWord 
    ? 'w-10 h-10 md:w-12 md:h-12 text-lg' 
    : 'w-12 h-12 md:w-16 md:h-16 text-xl md:text-2xl';

  return (
    <div className="max-w-4xl mx-auto px-2 py-2 flex flex-col items-center space-y-4 md:space-y-6 animate-in slide-in-from-bottom-4 duration-500">
      {/* Navigation & Progress */}
      <div className="w-full space-y-2 px-2">
        <div className="flex justify-between items-center">
          <button 
            onClick={onBack}
            className="flex items-center space-x-1 text-indigo-600 hover:text-indigo-800 font-bold transition-colors group"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 transform group-hover:-translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
            </svg>
            <span className="text-xs">Back</span>
          </button>
          <span className="text-[10px] md:text-xs font-bold text-slate-400 uppercase tracking-widest">
            Word {currentIndex + 1} of {words.length}
          </span>
        </div>
        <div className="w-full bg-white rounded-full h-1.5 md:h-2.5 relative overflow-hidden shadow-sm border border-slate-100">
          <div 
            className="h-full bg-indigo-500 transition-all duration-500 ease-out"
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>

      {/* Audio Section - Scaled for vertical space */}
      <div className="flex flex-col items-center space-y-2">
        <button 
          onClick={() => playAmericanPronunciation(currentWord)}
          className="w-16 h-16 md:w-24 md:h-24 bg-white rounded-full shadow-lg border-2 md:border-4 border-indigo-50 flex items-center justify-center hover:scale-105 hover:shadow-indigo-100 transition-all active:scale-95 group"
          aria-label="Play pronunciation"
        >
          <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 md:h-10 md:w-10 text-indigo-500 group-hover:text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
          </svg>
        </button>
        <p className="text-indigo-400 text-[8px] md:text-[10px] font-bold tracking-[0.2em] uppercase">Listen carefully</p>
      </div>

      {/* Spelling Area (Slots) */}
      <div className="flex flex-wrap justify-center gap-1.5 md:gap-3 min-h-[60px] md:min-h-[100px] w-full py-2">
        {selectedLetters.map((letter, i) => (
          <div 
            key={`slot-${i}`}
            onClick={() => undoLetter(i)}
            className={`${slotSizeClass} border-b-2 md:border-b-4 flex items-center justify-center font-bold cursor-pointer transition-all
              ${isWrong ? 'border-red-400 text-red-500 animate-shake' : 'border-indigo-100 text-indigo-900 hover:border-indigo-300'}
              ${letter ? 'bg-white rounded-t-lg md:rounded-t-xl shadow-md border-indigo-200' : 'bg-indigo-50/10'}
            `}
          >
            {letter || ''}
          </div>
        ))}
      </div>

      {/* Letter Pool - Compact and Borderless */}
      <div className="flex flex-wrap justify-center gap-2 md:gap-4 p-2 w-full">
        {scrambledLetters.map((letter, i) => (
          <button
            key={`pool-${letter}-${i}`}
            onClick={() => handleLetterClick(letter, i)}
            className={`${poolSizeClass} bg-white rounded-xl shadow-sm md:shadow-md border border-slate-100 text-indigo-700 
                       font-bold hover:translate-y-[-2px] md:hover:translate-y-[-4px] hover:shadow-lg hover:border-indigo-200 transition-all active:scale-90`}
          >
            {letter}
          </button>
        ))}
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .animate-shake {
          animation: shake 0.2s ease-in-out 3;
        }
      `}</style>
    </div>
  );
};

export default SpellingGame;

import React, { useEffect, useState } from 'react';
import { ScoreData } from '../types';
import { getAIFeedback } from '../services/geminiService';

interface ResultsProps {
  scoreData: ScoreData;
  onRestart: () => void;
}

const Results: React.FC<ResultsProps> = ({ scoreData, onRestart }) => {
  const [aiFeedback, setAiFeedback] = useState("Generating evaluation...");
  const { totalScore, correctFirstTry, totalWords } = scoreData;

  useEffect(() => {
    const fetchFeedback = async () => {
      const fb = await getAIFeedback(totalScore);
      setAiFeedback(fb);
    };
    fetchFeedback();
  }, [totalScore]);

  const getRank = () => {
    if (totalScore >= 90) return { title: 'Master', color: 'text-red-500', bg: 'bg-red-50' };
    if (totalScore >= 80) return { title: 'Excellent', color: 'text-orange-500', bg: 'bg-orange-50' };
    if (totalScore >= 60) return { title: 'Great Job', color: 'text-blue-500', bg: 'bg-blue-50' };
    if (totalScore >= 40) return { title: 'On Track', color: 'text-green-500', bg: 'bg-green-50' };
    return { title: 'Keep Trying', color: 'text-slate-500', bg: 'bg-slate-50' };
  };

  const rank = getRank();

  return (
    <div className="max-w-xl mx-auto p-4 md:p-10 flex flex-col items-center animate-in zoom-in duration-500">
      <div className={`w-32 h-32 md:w-48 md:h-48 rounded-full flex flex-col items-center justify-center shadow-xl border-4 md:border-8 border-white ${rank.bg} mb-4 md:mb-8 transform hover:scale-105 transition-transform`}>
        <span className={`text-4xl md:text-7xl font-kids ${rank.color}`}>{totalScore}</span>
        <span className="text-[8px] md:text-xs font-bold text-slate-400 uppercase tracking-widest mt-1">Points</span>
      </div>

      <h2 className={`text-2xl md:text-4xl font-kids mb-1 md:mb-2 ${rank.color}`}>{rank.title}</h2>

      <div className="bg-white rounded-2xl md:rounded-3xl p-6 md:p-10 shadow-sm border border-slate-100 w-full mb-6 md:mb-8 text-center space-y-4 md:space-y-6">
        <div className="grid grid-cols-2 gap-3 md:gap-6">
          <div className="p-3 md:p-6 bg-slate-50 rounded-xl md:rounded-2xl border border-slate-100">
            <p className="text-[8px] md:text-xs text-slate-400 uppercase font-bold mb-1 tracking-wider">Total Words</p>
            <p className="text-xl md:text-3xl font-kids text-slate-700">{totalWords}</p>
          </div>
          <div className="p-3 md:p-6 bg-slate-50 rounded-xl md:rounded-2xl border border-slate-100">
            <p className="text-[8px] md:text-xs text-slate-400 uppercase font-bold mb-1 tracking-wider">Perfect</p>
            <p className="text-xl md:text-3xl font-kids text-indigo-500">{correctFirstTry}</p>
          </div>
        </div>

        <div className="pt-4 md:pt-6 border-t border-slate-100">
          <p className="text-slate-600 text-xs md:text-sm font-medium leading-relaxed italic">
            "{aiFeedback}"
          </p>
        </div>
      </div>

      <button
        onClick={onRestart}
        className="px-8 md:px-12 py-3 md:py-5 bg-indigo-600 text-white rounded-xl md:rounded-2xl font-bold shadow-xl shadow-indigo-100 hover:bg-indigo-700 hover:-translate-y-1 active:translate-y-0 transition-all flex items-center space-x-2"
      >
        <span className="text-sm md:text-base">Test Again</span>
        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 md:h-5 md:w-5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
        </svg>
      </button>
    </div>
  );
