        </div>
        <div className="w-full bg-white rounded-full h-1.5 md:h-2 relative overflow-hidden shadow-inner border border-slate-100">
          <div 
            className="h-full bg-indigo-500 transition-all duration-500 ease-out"
            style={{ width: `${progress}%` }}
          />
        </div>
