import React, { useState } from 'react';
import { GameState, LexileRange, Word, ScoreData } from './types';
import { LEXILE_WORDS } from './constants';
import LexileSelector from './components/LexileSelector';
import SpellingGame from './components/SpellingGame';
import Results from './components/Results';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [currentWords, setCurrentWords] = useState<Word[]>([]);
  const [scoreData, setScoreData] = useState<ScoreData | null>(null);

  const startTest = (range: LexileRange) => {
    const pool = LEXILE_WORDS[range];
    const shuffled = [...pool].sort(() => 0.5 - Math.random());
    // Reduced to 5 words for testing as requested
    const selected = shuffled.slice(0, 5);

    setCurrentWords(selected);
    setGameState(GameState.PLAYING);
  };

  const handleFinish = (data: ScoreData) => {
    setScoreData(data);
    setGameState(GameState.FINISHED);
  };

  const resetGame = () => {
    setGameState(GameState.START);
    setScoreData(null);
    setCurrentWords([]);
  };

  return (
    <div className="h-screen flex flex-col px-4 py-2 md:py-4 selection:bg-indigo-100 transition-colors overflow-hidden relative">
      {/* Header - Fixed Height & Compact */}
      <header className={`flex-none max-w-6xl w-full mx-auto ${gameState === GameState.PLAYING ? 'mb-2 md:mb-4' : 'mb-4 md:mb-6'} flex justify-between items-center z-20`}>
        <div className="flex items-center space-x-2 md:space-x-3 cursor-pointer group" onClick={resetGame}>
          <div className="w-8 h-8 md:w-12 md:h-12 bg-indigo-600 rounded-lg md:rounded-2xl flex items-center justify-center shadow-lg shadow-indigo-100 group-hover:rotate-12 transition-transform">
            <span className="text-white font-kids text-lg md:text-2xl">L</span>
          </div>
          <div>
            <h1 className="text-lg md:text-2xl font-kids text-indigo-900 leading-none">Lexile Master</h1>
            <p className="text-[7px] md:text-[10px] text-slate-400 font-bold uppercase tracking-[0.2em]">Spelling Challenge</p>
          </div>
        </div>
      </header>

      {/* Main Content - Scrollable only if needed */}
      <main className="flex-1 max-w-6xl w-full mx-auto relative z-10 overflow-y-auto no-scrollbar">
        {gameState === GameState.START && (
          <LexileSelector onSelect={startTest} />
        )}

        {gameState === GameState.PLAYING && currentWords.length > 0 && (
          <SpellingGame 
            words={currentWords} 
            onFinish={handleFinish} 
            onBack={resetGame}
          />
        )}

        {gameState === GameState.FINISHED && scoreData && (
          <Results 
            scoreData={scoreData} 
            onRestart={resetGame} 
          />
        )}
      </main>

      {/* Footer - Fixed at bottom */}
      <footer className="flex-none py-1 md:py-2 text-center z-20">
        <p className="text-[9px] md:text-xs text-slate-400 font-medium">
          &copy; 2025 Lexile Assessment System v1.0
        </p>
      </footer>

      {/* Decorative background elements */}
      <div className="fixed -bottom-32 -left-32 w-[300px] md:w-[500px] h-[300px] md:h-[500px] bg-indigo-100/40 rounded-full blur-[80px] md:blur-[120px] -z-0 animate-pulse pointer-events-none"></div>
      <div className="fixed -top-32 -right-32 w-[300px] md:w-[500px] h-[300px] md:h-[500px] bg-blue-100/40 rounded-full blur-[80px] md:blur-[120px] -z-0 animate-pulse delay-1000 pointer-events-none"></div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
      `}</style>
    </div>
  );
};

