import React, { useState, useEffect, useCallback } from 'react';
import { Word, ScoreData } from '../types';
import { playAmericanPronunciation } from '../services/geminiService';

interface SpellingGameProps {
  words: Word[];
  onFinish: (scoreData: ScoreData) => void;
  onBack: () => void;
}

const SpellingGame: React.FC<SpellingGameProps> = ({ words, onFinish, onBack }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedLetters, setSelectedLetters] = useState<(string | null)[]>([]);
  const [scrambledLetters, setScrambledLetters] = useState<string[]>([]);
  const [hasFailedThisWord, setHasFailedThisWord] = useState(false);
  const [correctFirstTryCount, setCorrectFirstTryCount] = useState(0);
  const [isWrong, setIsWrong] = useState(false);

  const currentWord = words[currentIndex].word;

  const shuffleLetters = useCallback((word: string) => {
    return word.split('').sort(() => Math.random() - 0.5);
  }, []);

  const initWord = useCallback(() => {
    setScrambledLetters(shuffleLetters(currentWord));
    setSelectedLetters(new Array(currentWord.length).fill(null));
    setHasFailedThisWord(false);
    setIsWrong(false);
    playAmericanPronunciation(currentWord);
  }, [currentWord, shuffleLetters]);

  useEffect(() => {
    initWord();
  }, [currentIndex, initWord]);

  const handleLetterClick = (letter: string, indexInPool: number) => {
    if (isWrong) return;

    const firstEmptyIndex = selectedLetters.indexOf(null);
    if (firstEmptyIndex === -1) return;

    const newScrambled = [...scrambledLetters];
    newScrambled.splice(indexInPool, 1);
    setScrambledLetters(newScrambled);

    const newSelected = [...selectedLetters];
    newSelected[firstEmptyIndex] = letter;
    setSelectedLetters(newSelected);

    if (newSelected.filter(l => l !== null).length === currentWord.length) {
      const spelledWord = newSelected.join('');
      if (spelledWord === currentWord) {
        if (!hasFailedThisWord) {
          setCorrectFirstTryCount(prev => prev + 1);
        }

        setTimeout(() => {
          if (currentIndex < words.length - 1) {
            setCurrentIndex(prev => prev + 1);
          } else {
            const finalCorrect = !hasFailedThisWord ? correctFirstTryCount + 1 : correctFirstTryCount;
            onFinish({
              totalScore: finalCorrect * 2, // 50 words * 2 points = 100 max
              correctFirstTry: finalCorrect,
              totalWords: words.length
            });
          }
        }, 600);
      } else {
        setIsWrong(true);
        setHasFailedThisWord(true);
        setTimeout(() => {
          setSelectedLetters(new Array(currentWord.length).fill(null));
          setScrambledLetters(shuffleLetters(currentWord));
          setIsWrong(false);
        }, 800);
      }
    }
  };

  const undoLetter = (indexInSlot: number) => {
    if (isWrong || selectedLetters[indexInSlot] === null) return;

    const letter = selectedLetters[indexInSlot];
    const newSelected = [...selectedLetters];
    newSelected[indexInSlot] = null; 
    setSelectedLetters(newSelected);

    setScrambledLetters(prev => [...prev, letter!]);
  };

  const progress = ((currentIndex) / words.length) * 100;

  const isLongWord = currentWord.length > 8;

  // Larger font sizes for better visibility, compact box sizes for fit
  const slotSizeClass = isLongWord 
    ? 'w-7 h-9 md:w-11 md:h-14 text-xl md:text-2xl' 
    : 'w-9 h-12 md:w-16 md:h-20 text-2xl md:text-4xl';
  const poolSizeClass = isLongWord 
    ? 'w-9 h-9 md:w-12 md:h-12 text-lg md:text-xl' 
    : 'w-11 h-11 md:w-16 md:h-16 text-xl md:text-3xl';

  return (
    <div className="h-full flex flex-col animate-in slide-in-from-bottom-4 duration-500 overflow-hidden px-1">
      {/* Header - Compressed */}
      <div className="flex-none w-full mb-1">
        <div className="flex justify-between items-center px-1 py-1">
          <button 
            onClick={onBack}
            className="flex items-center space-x-1 px-3 py-1 bg-white border border-slate-200 rounded-full text-indigo-600 hover:bg-indigo-50 font-bold transition-all shadow-sm active:scale-95 group"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3 transform group-hover:-translate-x-0.5 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
            </svg>
            <span className="text-[10px] md:text-xs">Back</span>
          </button>
          <div className="text-right">
            <span className="text-[10px] font-black text-indigo-600">
               {currentIndex + 1} / {words.length}
            </span>
          </div>
        </div>
        <div className="w-full bg-slate-100 rounded-full h-1 relative overflow-hidden shadow-inner">
          <div 
            className="h-full bg-indigo-500 transition-all duration-500 ease-out"
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>

      {/* Main Gameplay - Centered with tight spacing */}
      <div className="flex-1 flex flex-col items-center justify-center space-y-2 md:space-y-4 overflow-hidden py-1">
        {/* Audio Button - Scaled down for height conservation */}
        <div className="flex flex-col items-center space-y-0.5">
          <button 
            onClick={() => playAmericanPronunciation(currentWord)}
            className="w-12 h-12 md:w-20 md:h-20 bg-white rounded-full shadow-md border-2 border-white flex items-center justify-center hover:scale-105 transition-all active:scale-95 group ring-2 ring-indigo-50/50"
            aria-label="Play pronunciation"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 md:h-10 md:w-10 text-indigo-500 group-hover:text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
            </svg>
          </button>
          <span className="text-indigo-300 text-[7px] md:text-[8px] font-bold uppercase tracking-widest">Listen</span>
        </div>

        {/* Spelling Slots - Core content enlarged font */}
        <div className="flex flex-wrap justify-center gap-1 md:gap-2 w-full px-1">
          {selectedLetters.map((letter, i) => (
            <div 
              key={`slot-${i}`}
              onClick={() => undoLetter(i)}
              className={`${slotSizeClass} border-b-2 md:border-b-[3px] flex items-center justify-center font-black cursor-pointer transition-all
                ${isWrong ? 'border-red-400 text-red-500 animate-shake' : 'border-slate-200 text-indigo-900 hover:border-indigo-400'}
                ${letter ? 'bg-white rounded-t-lg shadow-sm border-b-indigo-500' : 'bg-slate-50/30 rounded-t-md'}
              `}
            >
              {letter || ''}
            </div>
          ))}
        </div>

        {/* Letter Pool - More compact but larger letters */}
        <div className="flex flex-wrap justify-center gap-1.5 md:gap-2 max-w-lg mx-auto py-1">
          {scrambledLetters.map((letter, i) => (
            <button
              key={`pool-${letter}-${i}`}
              onClick={() => handleLetterClick(letter, i)}
              className={`${poolSizeClass} bg-white rounded-lg md:rounded-xl shadow-sm border border-slate-100 text-indigo-700 
                         font-bold hover:translate-y-[-1px] hover:shadow-md hover:bg-indigo-50 transition-all active:scale-90`}
            >
              {letter}
            </button>
          ))}
        </div>
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-3px); }
          75% { transform: translateX(3px); }
        }
        .animate-shake {
          animation: shake 0.2s ease-in-out 3;
        }
      `}</style>
    </div>
  );
};

