import React, { useState, useEffect, useCallback } from 'react';
import { Word, ScoreData } from '../types';
import { playAmericanPronunciation } from '../services/geminiService';

interface SpellingGameProps {
  words: Word[];
  onFinish: (scoreData: ScoreData) => void;
  onBack: () => void;
}

const SpellingGame: React.FC<SpellingGameProps> = ({ words, onFinish, onBack }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedLetters, setSelectedLetters] = useState<(string | null)[]>([]);
  const [scrambledLetters, setScrambledLetters] = useState<string[]>([]);
  const [hasFailedThisWord, setHasFailedThisWord] = useState(false);
  const [correctFirstTryCount, setCorrectFirstTryCount] = useState(0);
  const [isWrong, setIsWrong] = useState(false);

  const currentWord = words[currentIndex].word;

  const shuffleLetters = useCallback((word: string) => {
    return word.split('').sort(() => Math.random() - 0.5);
  }, []);

  const initWord = useCallback(() => {
    setScrambledLetters(shuffleLetters(currentWord));
    setSelectedLetters(new Array(currentWord.length).fill(null));
    setHasFailedThisWord(false);
    setIsWrong(false);
    playAmericanPronunciation(currentWord);
  }, [currentWord, shuffleLetters]);

  useEffect(() => {
    initWord();
  }, [currentIndex, initWord]);

  const handleLetterClick = (letter: string, indexInPool: number) => {
    if (isWrong) return;

    const firstEmptyIndex = selectedLetters.indexOf(null);
    if (firstEmptyIndex === -1) return;

    const newScrambled = [...scrambledLetters];
    newScrambled.splice(indexInPool, 1);
    setScrambledLetters(newScrambled);

    const newSelected = [...selectedLetters];
    newSelected[firstEmptyIndex] = letter;
    setSelectedLetters(newSelected);

    if (newSelected.filter(l => l !== null).length === currentWord.length) {
      const spelledWord = newSelected.join('');
      if (spelledWord === currentWord) {
        if (!hasFailedThisWord) {
          setCorrectFirstTryCount(prev => prev + 1);
        }

        setTimeout(() => {
          if (currentIndex < words.length - 1) {
            setCurrentIndex(prev => prev + 1);
          } else {
            const finalCorrect = !hasFailedThisWord ? correctFirstTryCount + 1 : correctFirstTryCount;
            onFinish({
              totalScore: finalCorrect * 2, 
              correctFirstTry: finalCorrect,
              totalWords: words.length
            });
          }
        }, 600);
      } else {
        setIsWrong(true);
        setHasFailedThisWord(true);
        setTimeout(() => {
          setSelectedLetters(new Array(currentWord.length).fill(null));
          setScrambledLetters(shuffleLetters(currentWord));
          setIsWrong(false);
        }, 800);
      }
    }
  };

  const undoLetter = (indexInSlot: number) => {
    if (isWrong || selectedLetters[indexInSlot] === null) return;

    const letter = selectedLetters[indexInSlot];
    const newSelected = [...selectedLetters];
    newSelected[indexInSlot] = null; 
    setSelectedLetters(newSelected);

    setScrambledLetters(prev => [...prev, letter!]);
  };

  const progress = ((currentIndex) / words.length) * 100;

  const isLongWord = currentWord.length > 8;

  // CORE ELEMENT SIZES: Scaled up for readability, compact for height fit
  const slotSizeClass = isLongWord 
    ? 'w-8 h-10 md:w-12 md:h-16 text-2xl md:text-4xl' 
    : 'w-11 h-14 md:w-20 md:h-28 text-4xl md:text-6xl';
  const poolSizeClass = isLongWord 
    ? 'w-10 h-10 md:w-14 md:h-14 text-xl md:text-3xl' 
    : 'w-12 h-12 md:w-20 md:h-20 text-3xl md:text-5xl';

  return (
    <div className="h-full flex flex-col animate-in slide-in-from-bottom-2 duration-500 overflow-hidden px-1 pb-2">
      {/* Navigation & Progress Area - Highly compressed */}
      <div className="flex-none w-full">
        <div className="flex justify-between items-center px-2 py-2">
          {/* Beautifully styled Larger Back Button */}
          <button 
            onClick={onBack}
            className="flex items-center space-x-2 px-4 py-1.5 md:px-6 md:py-2 bg-white border-2 border-indigo-100 rounded-2xl text-indigo-600 hover:bg-indigo-50 font-black shadow-sm active:scale-95 transition-all group ring-1 ring-indigo-50/50"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 md:h-5 md:w-5 group-hover:-translate-x-1 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" />
            </svg>
            <span className="text-xs md:text-sm tracking-wide">EXIT</span>
          </button>
          <div className="text-right">
            <span className="text-xs md:text-sm font-black text-indigo-500 bg-indigo-50/50 px-3 py-1 rounded-lg">
               {currentIndex + 1} / {words.length}
            </span>
          </div>
        </div>
        <div className="w-full bg-slate-100 rounded-full h-1 relative overflow-hidden mx-1">
          <div 
            className="h-full bg-indigo-500 transition-all duration-500 ease-out shadow-[0_0_8px_rgba(99,102,241,0.6)]"
            style={{ width: `${progress}%` }}
          />
        </div>
      </div>

      {/* Primary Game Area - Centered and scaled */}
      <div className="flex-1 flex flex-col items-center justify-center space-y-4 md:space-y-8 overflow-hidden">

        {/* Pronunciation Section */}
        <div className="flex flex-col items-center space-y-1">
          <button 
            onClick={() => playAmericanPronunciation(currentWord)}
            className="w-14 h-14 md:w-24 md:h-24 bg-white rounded-full shadow-lg border-2 border-white flex items-center justify-center hover:scale-110 transition-all active:scale-90 group ring-4 ring-indigo-50/30"
            aria-label="Play pronunciation"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8 md:h-12 md:w-12 text-indigo-500 group-hover:text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
            </svg>
          </button>
          <span className="text-indigo-400 text-[9px] md:text-xs font-black uppercase tracking-widest opacity-60">Listen Word</span>
        </div>

        {/* Word Slots - ENLARGED FONT */}
        <div className="flex flex-wrap justify-center gap-2 md:gap-4 w-full px-2">
          {selectedLetters.map((letter, i) => (
            <div 
              key={`slot-${i}`}
              onClick={() => undoLetter(i)}
              className={`${slotSizeClass} border-b-[4px] md:border-b-[6px] flex items-center justify-center font-black cursor-pointer transition-all
                ${isWrong ? 'border-red-400 text-red-500 animate-shake' : 'border-slate-200 text-indigo-950 hover:border-indigo-400'}
                ${letter ? 'bg-white rounded-t-2xl shadow-xl border-b-indigo-500' : 'bg-slate-50/40 rounded-t-xl'}
              `}
            >
              {letter || ''}
            </div>
          ))}
        </div>

        {/* Letter Pool - ENLARGED FONT & COMPACT GRID */}
        <div className="flex flex-wrap justify-center gap-2 md:gap-4 max-w-2xl mx-auto px-2 py-2">
          {scrambledLetters.map((letter, i) => (
            <button
              key={`pool-${letter}-${i}`}
              onClick={() => handleLetterClick(letter, i)}
              className={`${poolSizeClass} bg-white rounded-xl md:rounded-3xl shadow-sm border-2 border-slate-50 text-indigo-800 
                         font-black hover:translate-y-[-2px] md:hover:translate-y-[-6px] hover:shadow-xl hover:bg-indigo-50/50 transition-all active:scale-90`}
            >
              {letter}
            </button>
          ))}
        </div>
      </div>

      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .animate-shake {
          animation: shake 0.2s ease-in-out 3;
        }
      `}</style>
    </div>
  );
};

