            <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6 md:h-10 md:w-10 text-indigo-500 group-hover:text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
            </svg>
          </button>
          <span className="text-indigo-400 text-[8px] md:text-[10px] font-black uppercase tracking-widest opacity-40">Listen</span>
        </div>

        {/* Word Slots */}
        <div className="flex flex-wrap justify-center gap-1.5 md:gap-3 w-full px-2">
          {selectedLetters.map((letter, i) => (
            <div 
              key={`slot-${i}`}
              onClick={() => undoLetter(i)}
              className={`${slotSizeClass} border-b-[3px] md:border-b-[4px] flex items-center justify-center font-black cursor-pointer transition-all
                ${isWrong ? 'border-red-400 text-red-500 animate-shake' : 'border-slate-200 text-indigo-950 hover:border-indigo-400'}
                ${letter ? 'bg-white rounded-t-xl shadow-lg border-b-indigo-500' : 'bg-slate-50/30 rounded-t-lg'}
              `}
            >
              {letter || ''}
            </div>
          ))}
        </div>

        {/* Letter Pool */}
        <div className="flex flex-wrap justify-center gap-1.5 md:gap-3 max-w-2xl mx-auto px-2 py-1">
          {scrambledLetters.map((letter, i) => (
            <button
              key={`pool-${letter}-${i}`}
              onClick={() => handleLetterClick(letter, i)}
              className={`${poolSizeClass} bg-white rounded-xl md:rounded-2xl shadow-sm border border-slate-50 text-indigo-800 
                         font-black hover:translate-y-[-2px] md:hover:translate-y-[-4px] hover:shadow-md hover:bg-indigo-50 transition-all active:scale-90`}
            >
              {letter}
            </button>
          ))}
