import React, { useState } from 'react';
import { GameState, LexileRange, Word, ScoreData } from './types';
import { LEXILE_WORDS } from './constants';
import LexileSelector from './components/LexileSelector';
import SpellingGame from './components/SpellingGame';
import Results from './components/Results';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.START);
  const [currentWords, setCurrentWords] = useState<Word[]>([]);
  const [scoreData, setScoreData] = useState<ScoreData | null>(null);

  const startTest = (range: LexileRange) => {
    const pool = LEXILE_WORDS[range];
    const shuffled = [...pool].sort(() => 0.5 - Math.random());
    const selected = shuffled.slice(0, 50);

    setCurrentWords(selected);
    setGameState(GameState.PLAYING);
  };

  const handleFinish = (data: ScoreData) => {
    setScoreData(data);
    setGameState(GameState.FINISHED);
  };

  const resetGame = () => {
    setGameState(GameState.START);
    setScoreData(null);
    setCurrentWords([]);
  };

  return (
    <div className="h-screen flex flex-col px-2 py-0 selection:bg-indigo-100 transition-colors overflow-hidden relative bg-slate-50">
      {/* Header - Dynamically scales with gameState */}
      <header className={`flex-none w-full mx-auto ${gameState === GameState.PLAYING ? 'h-[8vh] md:h-[6vh]' : 'h-[12vh] md:h-[10vh] mt-2'} flex flex-col items-center justify-center z-20 transition-all duration-500`}>
        <div className="flex flex-col items-center cursor-pointer group" onClick={() => gameState !== GameState.PLAYING && resetGame()}>
          <div className="w-6 h-6 md:w-8 md:h-8 bg-indigo-600 rounded-lg flex items-center justify-center shadow-md shadow-indigo-100 group-hover:rotate-12 transition-transform mb-0.5">
            <span className="text-white font-kids text-sm md:text-base leading-none">L</span>
          </div>
          <div className="text-center">
            <h1 className="text-sm md:text-base font-kids text-indigo-900 leading-none">Lexile Master</h1>
            <p className="text-[5px] md:text-[7px] text-slate-400 font-bold uppercase tracking-[0.2em] leading-none mt-0.5">Assessment v1.0</p>
          </div>
        </div>
      </header>

      {/* Main Content Area - Strictly takes remaining space */}
      <main className="flex-1 max-w-6xl w-full mx-auto relative z-10 overflow-hidden flex flex-col">
        {gameState === GameState.START && (
          <div className="flex-1 overflow-y-auto no-scrollbar">
            <LexileSelector onSelect={startTest} />
          </div>
        )}

        {gameState === GameState.PLAYING && currentWords.length > 0 && (
          <div className="flex-1 flex flex-col h-full overflow-hidden">
            <SpellingGame 
              words={currentWords} 
              onFinish={handleFinish} 
              onBack={resetGame}
            />
          </div>
        )}

        {gameState === GameState.FINISHED && scoreData && (
          <div className="flex-1 overflow-y-auto no-scrollbar">
            <Results 
              scoreData={scoreData} 
              onRestart={resetGame} 
            />
          </div>
        )}
      </main>

      {/* Footer - Minimalist */}
      <footer className="flex-none h-[2vh] text-center z-20 flex items-center justify-center">
        <p className="text-[6px] md:text-[8px] text-slate-300 font-medium">
          &copy; 2025 Lexile Assessment System
        </p>
      </footer>

      {/* Background Decor */}
      <div className="fixed -bottom-20 -left-20 w-48 h-48 bg-indigo-50/10 rounded-full blur-3xl -z-0 pointer-events-none"></div>
      <div className="fixed -top-20 -right-20 w-48 h-48 bg-blue-50/10 rounded-full blur-3xl -z-0 pointer-events-none"></div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { Word, ScoreData } from '../types';
import { playAmericanPronunciation } from '../services/geminiService';

interface SpellingGameProps {
  words: Word[];
  onFinish: (scoreData: ScoreData) => void;
  onBack: () => void;
}

const SpellingGame: React.FC<SpellingGameProps> = ({ words, onFinish, onBack }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedLetters, setSelectedLetters] = useState<(string | null)[]>([]);
  const [scrambledLetters, setScrambledLetters] = useState<string[]>([]);
  const [hasFailedThisWord, setHasFailedThisWord] = useState(false);
  const [correctFirstTryCount, setCorrectFirstTryCount] = useState(0);
  const [isWrong, setIsWrong] = useState(false);
  const [showExitConfirm, setShowExitConfirm] = useState(false);

  const currentWord = words[currentIndex].word;

  const shuffleLetters = useCallback((word: string) => {
    return word.split('').sort(() => Math.random() - 0.5);
  }, []);

  const initWord = useCallback(() => {
    setScrambledLetters(shuffleLetters(currentWord));
    setSelectedLetters(new Array(currentWord.length).fill(null));
    setHasFailedThisWord(false);
    setIsWrong(false);
    playAmericanPronunciation(currentWord);
  }, [currentWord, shuffleLetters]);

  useEffect(() => {
    initWord();
  }, [currentIndex, initWord]);

  const handleLetterClick = (letter: string, indexInPool: number) => {
    if (isWrong) return;

    const firstEmptyIndex = selectedLetters.indexOf(null);
    if (firstEmptyIndex === -1) return;

    const newScrambled = [...scrambledLetters];
    newScrambled.splice(indexInPool, 1);
    setScrambledLetters(newScrambled);

    const newSelected = [...selectedLetters];
    newSelected[firstEmptyIndex] = letter;
    setSelectedLetters(newSelected);

    if (newSelected.filter(l => l !== null).length === currentWord.length) {
      const spelledWord = newSelected.join('');
      if (spelledWord === currentWord) {
        if (!hasFailedThisWord) {
          setCorrectFirstTryCount(prev => prev + 1);
        }

        setTimeout(() => {
          if (currentIndex < words.length - 1) {
            setCurrentIndex(prev => prev + 1);
          } else {
            const finalCorrect = !hasFailedThisWord ? correctFirstTryCount + 1 : correctFirstTryCount;
            onFinish({
              totalScore: finalCorrect * 2, 
              correctFirstTry: finalCorrect,
              totalWords: words.length
            });
          }
        }, 600);
      } else {
        setIsWrong(true);
        setHasFailedThisWord(true);
        setTimeout(() => {
          setSelectedLetters(new Array(currentWord.length).fill(null));
          setScrambledLetters(shuffleLetters(currentWord));
          setIsWrong(false);
        }, 800);
      }
    }
  };

  const undoLetter = (indexInSlot: number) => {
    if (isWrong || selectedLetters[indexInSlot] === null) return;

    const letter = selectedLetters[indexInSlot];
    const newSelected = [...selectedLetters];
    newSelected[indexInSlot] = null; 
    setSelectedLetters(newSelected);

    setScrambledLetters(prev => [...prev, letter!]);
  };

  const progress = ((currentIndex) / words.length) * 100;

  // DYNAMIC SCALING LOGIC
  const wordLen = currentWord.length;
  const isExtraLong = wordLen > 10;
  const isLong = wordLen > 7;

  return (
    <div className="flex-1 flex flex-col animate-in slide-in-from-bottom-2 duration-500 overflow-hidden px-1">
      {/* HUD - Tighter Height */}
      <div className="flex-none w-full mb-1">
        <div className="flex justify-between items-center px-4 py-1">
          <button 
            onClick={() => setShowExitConfirm(true)}
            className="flex items-center space-x-2 px-4 py-1.5 md:py-2 bg-white border border-indigo-200 rounded-xl text-indigo-600 hover:bg-indigo-50 font-bold shadow-sm active:scale-95 transition-all group ring-1 ring-indigo-50/50"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 group-hover:-translate-x-0.5 transition-transform" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" />
            </svg>
            <span className="text-xs md:text-sm tracking-wide">EXIT</span>
          </button>
          <div className="text-right">
            <span className="text-xs md:text-sm font-black text-indigo-500 bg-white border border-indigo-50 px-3 py-1 rounded-lg shadow-sm">
               {currentIndex + 1} <span className="text-slate-300 font-normal">/</span> {words.length}
            </span>
          </div>
        </div>
        <div className="px-4">
          <div className="w-full bg-slate-200/50 rounded-full h-1.5 relative overflow-hidden">
            <div 
              className="h-full bg-indigo-500 transition-all duration-500 ease-out shadow-[0_0_8px_rgba(99,102,241,0.5)]"
              style={{ width: `${progress}%` }}
            />
          </div>
        </div>
      </div>

      {/* Main Game Container - Uses flex-around/center for vertical distribution */}
      <div className="flex-1 flex flex-col items-center justify-around py-2 overflow-hidden">

        {/* Audio Button - Scaled by Viewport Height */}
        <div className="flex flex-col items-center space-y-1">
          <button 
            onClick={() => playAmericanPronunciation(currentWord)}
            className="game-audio-btn flex items-center justify-center bg-white rounded-full shadow-lg border-2 border-white hover:scale-105 transition-all active:scale-90 group ring-4 ring-indigo-50/30"
            aria-label="Play pronunciation"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="w-[60%] h-[60%] text-indigo-500 group-hover:text-indigo-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
            </svg>
          </button>
          <span className="text-indigo-400 text-[9px] md:text-[11px] font-black uppercase tracking-[0.2em] opacity-50">Listen Accent</span>
        </div>

        {/* Word Slots - Dynamically Sized */}
        <div className={`flex flex-wrap justify-center gap-1 md:gap-3 w-full px-4`}>
          {selectedLetters.map((letter, i) => (
            <div 
              key={`slot-${i}`}
              onClick={() => undoLetter(i)}
              className={`game-slot border-b-[3px] md:border-b-[5px] flex items-center justify-center font-black cursor-pointer transition-all
                ${isExtraLong ? 'w-8 h-10 md:w-14 md:h-18 text-2xl md:text-4xl' : isLong ? 'w-10 h-14 md:w-16 md:h-22 text-3xl md:text-5xl' : 'w-12 h-16 md:w-24 md:h-32 text-4xl md:text-7xl'}
                ${isWrong ? 'border-red-400 text-red-500 animate-shake' : 'border-slate-200 text-indigo-950 hover:border-indigo-400'}
                ${letter ? 'bg-white rounded-t-xl shadow-xl border-b-indigo-500' : 'bg-slate-100/50 rounded-t-lg'}
              `}
            >
              {letter || ''}
            </div>
          ))}
        </div>

        {/* Letter Pool - Horizontal grid */}
        <div className="flex flex-wrap justify-center gap-1.5 md:gap-3 max-w-4xl mx-auto px-4">
          {scrambledLetters.map((letter, i) => (
            <button
              key={`pool-${letter}-${i}`}
              onClick={() => handleLetterClick(letter, i)}
              className={`game-pool-btn bg-white rounded-xl md:rounded-2xl shadow-sm border border-slate-100 text-indigo-800 
                         font-black hover:translate-y-[-2px] hover:shadow-md hover:bg-indigo-50 transition-all active:scale-90
                         ${isExtraLong ? 'w-9 h-9 md:w-14 md:h-14 text-xl md:text-3xl' : 'w-11 h-11 md:w-20 md:h-20 text-3xl md:text-5xl'}
              `}
            >
              {letter}
            </button>
          ))}
        </div>
      </div>

      {/* Exit Confirmation Modal */}
      {showExitConfirm && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-[2rem] p-8 max-w-sm w-full shadow-2xl animate-in zoom-in duration-200 text-center">
            <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-4 border-4 border-white shadow-inner">
              <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
            </div>
            <h3 className="text-xl md:text-2xl font-kids text-slate-800 mb-2">Wait! Leaving?</h3>
            <p className="text-slate-500 text-sm md:text-base mb-6">Are you sure you want to stop? You'll lose your current test results.</p>
            <div className="flex flex-col gap-2">
              <button 
                onClick={onBack}
                className="w-full py-4 bg-red-500 text-white rounded-2xl font-bold hover:bg-red-600 transition-colors shadow-lg shadow-red-100"
              >
                Yes, Stop and Exit
              </button>
              <button 
                onClick={() => setShowExitConfirm(false)}
                className="w-full py-3 bg-white text-slate-400 rounded-xl font-bold hover:text-slate-600 transition-all"
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      <style>{`
        /* Vertical Adaptive Scaling */
        .game-audio-btn {
          width: clamp(3.5rem, 15vh, 6rem);
          height: clamp(3.5rem, 15vh, 6rem);
        }

        @media (max-height: 700px) {
          .game-slot {
            height: clamp(3rem, 12vh, 5rem);
          }
          .game-pool-btn {
            width: clamp(2.5rem, 10vh, 4rem);
            height: clamp(2.5rem, 10vh, 4rem);
            font-size: clamp(1rem, 5vh, 2rem);
          }
          .game-audio-btn {
            width: clamp(3rem, 10vh, 5rem);
            height: clamp(3rem, 10vh, 5rem);
          }
        }

        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-4px); }
          75% { transform: translateX(4px); }
        }
        .animate-shake {
          animation: shake 0.2s ease-in-out 3;
        }
      `}</style>
    </div>
  );
};

export default SpellingGame;

