import React, { useEffect, useState } from 'react';
import { ScoreData } from '../types';
import { getAIFeedback } from '../services/geminiService';

interface ResultsProps {
  scoreData: ScoreData;
  onRestart: () => void;
}

const Results: React.FC<ResultsProps> = ({ scoreData, onRestart }) => {
  const [aiFeedback, setAiFeedback] = useState("Generating evaluation...");
  const { totalScore, correctFirstTry, totalWords } = scoreData;

  useEffect(() => {
    const fetchFeedback = async () => {
      const fb = await getAIFeedback(totalScore);
      setAiFeedback(fb);
    };
    fetchFeedback();
  }, [totalScore]);

  const getRank = () => {
    if (totalScore >= 90) return { title: 'Master', color: 'text-red-500', bg: 'bg-red-50' };
    if (totalScore >= 80) return { title: 'Excellent', color: 'text-orange-500', bg: 'bg-orange-50' };
    if (totalScore >= 60) return { title: 'Great Job', color: 'text-blue-500', bg: 'bg-blue-50' };
    if (totalScore >= 40) return { title: 'On Track', color: 'text-green-500', bg: 'bg-green-50' };
    return { title: 'Keep Trying', color: 'text-slate-500', bg: 'bg-slate-50' };
  };

  const rank = getRank();

  return (
    <div className="h-full flex flex-col items-center justify-center p-4 animate-in zoom-in duration-500 overflow-hidden">
      <div className={`w-28 h-28 md:w-36 md:h-36 rounded-full flex flex-col items-center justify-center shadow-lg border-4 border-white ${rank.bg} mb-4 flex-none`}>
        <span className={`text-4xl md:text-5xl font-kids ${rank.color}`}>{totalScore}</span>
        <span className="text-[7px] font-bold text-slate-400 uppercase tracking-widest">Points</span>
      </div>

      <h2 className={`text-2xl md:text-3xl font-kids mb-4 ${rank.color}`}>{rank.title}</h2>

      <div className="bg-white rounded-[2rem] p-6 shadow-sm border border-slate-100 w-full max-w-sm mb-6 text-center space-y-4">
        <div className="grid grid-cols-2 gap-4">
