            <p className="text-[8px] text-slate-400 uppercase font-bold mb-1">Words</p>
            <p className="text-xl font-kids text-slate-700">{totalWords}</p>
          </div>
          <div className="p-3 bg-slate-50 rounded-xl border border-slate-100">
            <p className="text-[8px] text-slate-400 uppercase font-bold mb-1">Perfect</p>
            <p className="text-xl font-kids text-indigo-500">{correctFirstTry}</p>
          </div>
        </div>

        <div className="pt-2">
          <p className="text-slate-600 text-[11px] md:text-xs font-medium leading-relaxed italic">
            "{aiFeedback}"
          </p>
        </div>
      </div>

      <button
        onClick={onRestart}
        className="px-8 py-3.5 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all flex items-center space-x-2"
      >
        <span className="text-sm">Restart Test</span>
        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
