import React, { useState, useEffect, useCallback } from 'react';
import { Word, ScoreData } from '../types';
import { playAmericanPronunciation } from '../services/geminiService';

interface SpellingGameProps {
  words: Word[];
  onFinish: (scoreData: ScoreData) => void;
  onBack: () => void;
}

const SpellingGame: React.FC<SpellingGameProps> = ({ words, onFinish, onBack }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [selectedLetters, setSelectedLetters] = useState<(string | null)[]>([]);
  const [scrambledLetters, setScrambledLetters] = useState<string[]>([]);
  const [hasFailedThisWord, setHasFailedThisWord] = useState(false);
  const [correctFirstTryCount, setCorrectFirstTryCount] = useState(0);
  const [isWrong, setIsWrong] = useState(false);
  const [showExitConfirm, setShowExitConfirm] = useState(false);

  const currentWord = words[currentIndex].word;

  const shuffleLetters = useCallback((word: string) => {
    return word.split('').sort(() => Math.random() - 0.5);
  }, []);

  const initWord = useCallback(() => {
    setScrambledLetters(shuffleLetters(currentWord));
    setSelectedLetters(new Array(currentWord.length).fill(null));
    setHasFailedThisWord(false);
    setIsWrong(false);
    playAmericanPronunciation(currentWord);
  }, [currentWord, shuffleLetters]);

  useEffect(() => {
    initWord();
  }, [currentIndex, initWord]);

  const handleLetterClick = (letter: string, indexInPool: number) => {
    if (isWrong) return;

    const firstEmptyIndex = selectedLetters.indexOf(null);
    if (firstEmptyIndex === -1) return;

    const newScrambled = [...scrambledLetters];
    newScrambled.splice(indexInPool, 1);
    setScrambledLetters(newScrambled);

    const newSelected = [...selectedLetters];
    newSelected[firstEmptyIndex] = letter;
    setSelectedLetters(newSelected);

    if (newSelected.filter(l => l !== null).length === currentWord.length) {
      const spelledWord = newSelected.join('');
      if (spelledWord === currentWord) {
        if (!hasFailedThisWord) {
          setCorrectFirstTryCount(prev => prev + 1);
        }

        setTimeout(() => {
          if (currentIndex < words.length - 1) {
            setCurrentIndex(prev => prev + 1);
          } else {
            const finalCorrect = !hasFailedThisWord ? correctFirstTryCount + 1 : correctFirstTryCount;
            onFinish({
              totalScore: finalCorrect * 2, 
              correctFirstTry: finalCorrect,
              totalWords: words.length
            });
          }
        }, 600);
      } else {
        setIsWrong(true);
        setHasFailedThisWord(true);
        setTimeout(() => {
          setSelectedLetters(new Array(currentWord.length).fill(null));
          setScrambledLetters(shuffleLetters(currentWord));
          setIsWrong(false);
        }, 800);
      }
    }
  };

  const undoLetter = (indexInSlot: number) => {
    if (isWrong || selectedLetters[indexInSlot] === null) return;

    const letter = selectedLetters[indexInSlot];
    const newSelected = [...selectedLetters];
    newSelected[indexInSlot] = null; 
    setSelectedLetters(newSelected);

    setScrambledLetters(prev => [...prev, letter!]);
  };

  const progress = ((currentIndex) / words.length) * 100;

  // DYNAMIC SCALING LOGIC
  const wordLen = currentWord.length;
  const isExtraLong = wordLen > 10;
  const isLong = wordLen > 7;

  return (
    <div className="flex-1 flex flex-col animate-in slide-in-from-bottom-2 duration-500 overflow-hidden px-1">
      {/* HUD - Tighter Height */}
      <div className="flex-none w-full">
        <div className="flex justify-between items-center px-4 py-1">
          <button 
            onClick={() => setShowExitConfirm(true)}
            className="flex items-center space-x-1 px-3 py-1 bg-white border border-indigo-200 rounded-lg text-indigo-600 hover:bg-indigo-50 font-bold shadow-sm active:scale-95 transition-all"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M15 19l-7-7 7-7" />
            </svg>
            <span className="text-[10px] tracking-wide">EXIT</span>
          </button>
          <div className="text-right">
            <span className="text-[10px] font-black text-indigo-500 bg-white border border-indigo-50 px-2 py-0.5 rounded shadow-sm">
               {currentIndex + 1} / {words.length}
            </span>
          </div>
        </div>
        <div className="px-4">
          <div className="w-full bg-slate-200/50 rounded-full h-1 relative overflow-hidden">
            <div 
              className="h-full bg-indigo-500 transition-all duration-500 ease-out"
              style={{ width: `${progress}%` }}
            />
          </div>
        </div>
      </div>

      {/* Main Game Container - Tight Gaps */}
      <div className="flex-1 flex flex-col items-center justify-center gap-2 md:gap-4 py-1 overflow-hidden">

        {/* Audio Button */}
        <div className="flex flex-col items-center">
          <button 
            onClick={() => playAmericanPronunciation(currentWord)}
            className="game-audio-btn flex items-center justify-center bg-white rounded-full shadow-md border-2 border-white hover:scale-105 active:scale-90 transition-all ring-2 ring-indigo-50/30"
            aria-label="Play pronunciation"
          >
            <svg xmlns="http://www.w3.org/2000/svg" className="w-[50%] h-[50%] text-indigo-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M15.536 8.464a5 5 0 010 7.072m2.828-9.9a9 9 0 010 12.728M5.586 15H4a1 1 0 01-1-1v-4a1 1 0 011-1h1.586l4.707-4.707C10.923 3.663 12 4.109 12 5v14c0 .891-1.077 1.337-1.707.707L5.586 15z" />
            </svg>
          </button>
        </div>

        {/* Word Slots */}
        <div className="flex flex-wrap justify-center gap-1 md:gap-2 w-full px-4">
          {selectedLetters.map((letter, i) => (
            <div 
              key={`slot-${i}`}
              onClick={() => undoLetter(i)}
              className={`game-slot border-b-2 md:border-b-4 flex items-center justify-center font-black cursor-pointer transition-all
                ${isExtraLong ? 'w-7 h-9 md:w-12 md:h-16 text-xl md:text-3xl' : isLong ? 'w-9 h-12 md:w-14 md:h-20 text-2xl md:text-4xl' : 'w-11 h-14 md:w-20 md:h-28 text-3xl md:text-6xl'}
                ${isWrong ? 'border-red-400 text-red-500 animate-shake' : 'border-slate-200 text-indigo-950 hover:border-indigo-400'}
                ${letter ? 'bg-white rounded-t-lg shadow-md border-b-indigo-500' : 'bg-slate-100/40 rounded-t-md'}
              `}
            >
              {letter || ''}
            </div>
          ))}
        </div>

        {/* Letter Pool */}
        <div className="flex flex-wrap justify-center gap-1 md:gap-2 max-w-4xl mx-auto px-4">
          {scrambledLetters.map((letter, i) => (
            <button
              key={`pool-${letter}-${i}`}
              onClick={() => handleLetterClick(letter, i)}
              className={`game-pool-btn bg-white rounded-lg md:rounded-xl shadow-sm border border-slate-100 text-indigo-800 
                         font-black hover:bg-indigo-50 active:scale-90 transition-all
                         ${isExtraLong ? 'w-8 h-8 md:w-12 md:h-12 text-lg md:text-2xl' : 'w-10 h-10 md:w-16 md:h-16 text-2xl md:text-4xl'}
              `}
            >
              {letter}
            </button>
          ))}
        </div>
      </div>

      {/* Exit Confirmation Modal */}
      {showExitConfirm && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl p-6 max-w-xs w-full shadow-2xl animate-in zoom-in duration-200 text-center">
            <h3 className="text-lg font-kids text-slate-800 mb-2">Leave Challenge?</h3>
            <p className="text-slate-500 text-xs mb-6">Progress will be lost.</p>
            <div className="flex flex-col gap-2">
              <button 
                onClick={onBack}
                className="w-full py-3 bg-red-500 text-white rounded-xl font-bold hover:bg-red-600 transition-colors shadow-lg shadow-red-100"
              >
                Yes, Exit
              </button>
              <button 
                onClick={() => setShowExitConfirm(false)}
                className="w-full py-2 bg-white text-slate-400 rounded-lg font-bold hover:text-slate-600 transition-all"
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}

      <style>{`
        .game-audio-btn {
          width: clamp(2.5rem, 8vh, 4.5rem);
          height: clamp(2.5rem, 8vh, 4.5rem);
        }

        @media (max-height: 600px) {
          .game-slot {
            height: clamp(2.5rem, 10vh, 4rem);
          }
          .game-pool-btn {
            width: clamp(2rem, 8vh, 3.5rem);
            height: clamp(2rem, 8vh, 3.5rem);
          }
        }

        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          25% { transform: translateX(-3px); }
          75% { transform: translateX(3px); }
        }
        .animate-shake {
          animation: shake 0.2s ease-in-out 3;
        }
      `}</style>
    </div>
  );
};

export default SpellingGame;

